using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;


    // Get active design
    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get root component in this design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Get rip features
    Ptr features = rootComp->features();
    if (!features)
        return false;

    Ptr ripFeatures = features->ripFeatures();
    if (!ripFeatures)
        return false;

    Ptr bodies = rootComp->bRepBodies();

    Ptr body = bodies->item(0);

    Ptr edges = body->edges();

    Ptr vertices = body->vertices();

    // Create a between points rip
    Ptr gapDistance = ValueInput::createByReal(1.23);

    Ptr offset1 = ValueInput::createByReal(2.34);

    Ptr ripFeatureInput = ripFeatures->createRipFeatureInput();

    Ptr edge = edges->item(40);

    Ptr vertex = vertices->item(9);


    // Create the feature
    Ptr ripFeature = ripFeatures->add(ripFeatureInput);


    return true;
}
